<template><SiteLayout><section class="mx-auto max-w-7xl px-4 py-14"><h1 class="text-4xl font-black">Free Training</h1><div class="mt-8 grid gap-5 md:grid-cols-3"><article v-for="course in courses" :key="course.title" class="rounded border bg-white p-6"><p class="text-sm font-black text-emerald-700">{{ course.lessons }} lessons</p><h2 class="mt-2 text-xl font-black">{{ course.title }}</h2><p class="mt-3 text-slate-600">{{ course.summary }}</p></article></div></section></SiteLayout></template>
<script setup lang="ts">import { ref, onMounted } from 'vue';import SiteLayout from '../components/SiteLayout.vue';import { freeCourses } from '../data/siteContent';import { fetchCourses } from '../services/courseService';const courses=ref(freeCourses);onMounted(async()=>{try{const live=await fetchCourses();courses.value=live.filter(c=>!c.isPremium).map(c=>({title:c.title,summary:c.description||'Free cybersecurity course.',lessons:c.lessons?.length||0,level:'Free'}));}catch{}});</script>
